node -e "
const { pluginNamePattern } = require('./src/constants');

const testCases = [
  { id: '\t\nnodebb-plugin', expected: false, description: 'Tab and newline at start' },
  { id: 'notaplugin', expected: false, description: 'Does not start with nodebb-' },
  { id: 'nodebb-plugin-markdown', expected: true, description: 'Valid plugin' },
  { id: '@nodebb/nodebb-plugin-test', expected: true, description: 'Valid scoped plugin' },
  { id: 'nodebb-theme-test', expected: true, description: 'Valid theme' },
  { id: 'nodebb plugin test', expected: false, description: 'Contains spaces' },
];

let passed = 0;
let failed = 0;

testCases.forEach(test => {
  const result = pluginNamePattern.test(test.id);
  const match = result === test.expected ? '✓' : '✗';
  console.log(\`\${match} \${test.description}: \${result} (expected: \${test.expected})\`);
  if (result === test.expected) {
    passed++;
  } else {
    failed++;
  }
});

console.log(\`\nTotal: \${passed} passed, \${failed} failed\`);
"

